const useCouponStore = create((set, get) => ({
  couponCode: '',
  discount: 0,
  error: null,
  setCouponCode: (code) => set({ couponCode: code }),
  applyCoupon: async () => {
    const { couponCode, subtotal } = get();
    try {
      const res = await fetch(`/api/validate-coupon?code=${couponCode}&subtotal=${subtotal}`);
      const data = await res.json();
      if (data.valid) set({ discount: data.discountAmount, error: null });
      else set({ error: data.message, discount: 0 });
    } catch { set({ error: 'Erreur de validation', discount: 0 }); }
  }
}));
```

