function CouponInput() {
  const { couponCode, setCouponCode, applyCoupon, discount, error } = useCouponStore();
  return (
    <div>
      <input value={couponCode} onChange={e => setCouponCode(e.target.value)} placeholder="Code promo" />
      <button onClick={applyCoupon}>Appliquer</button>
      {discount > 0 && <p className="text-green-600">Réduction de {discount} € appliquée</p>}
      {error && <p className="text-red-500">{error}</p>}
    </div>
  );
}
